// Extract email metadata and split into one item per attachment
const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  const senderEmail = email.sender?.emailAddress?.address
    || email.from?.emailAddress?.address || 'unknown';
  const senderName = email.sender?.emailAddress?.name
    || email.from?.emailAddress?.name || '';
  const subject = email.subject || '(no subject)';
  const receivedAt = email.receivedDateTime || email.createdDateTime || new Date().toISOString();
  const messageId = email.id || '';

  // Get all binary keys (attachments downloaded by trigger)
  const binaryKeys = item.binary ? Object.keys(item.binary) : [];

  if (binaryKeys.length === 0) {
    // No binary attachments - skip
    continue;
  }

  for (const binaryKey of binaryKeys) {
    const binaryData = item.binary[binaryKey];
    const fileName = binaryData.fileName || `attachment_${Date.now()}`;
    const mimeType = binaryData.mimeType || 'application/octet-stream';
    const fileSize = binaryData.fileSize || 0;

    results.push({
      json: {
        senderEmail,
        senderName,
        subject,
        receivedAt,
        messageId,
        fileName,
        mimeType,
        fileSize,
        binaryKey,
        intakeTimestamp: new Date().toISOString(),
      },
      binary: {
        data: binaryData,
      },
    });
  }
}

if (results.length === 0) {
  results.push({ json: { _noAttachments: true } });
}

return results;

const crypto = require('crypto');
const items = $input.all();
const results = [];

for (const item of items) {
  const binaryData = item.binary?.data;
  let fileHash = 'no_binary';

  if (binaryData && binaryData.data) {
    // binaryData.data is base64 encoded
    const buffer = Buffer.from(binaryData.data, 'base64');
    fileHash = crypto.createHash('sha256').update(buffer).digest('hex');
  }

  const random4 = Math.random().toString(36).slice(2, 6);
  const docId = `DOC-${Date.now()}-${random4}`;

  results.push({
    json: {
      ...item.json,
      docId,
      fileHash,
    },
    binary: item.binary,
  });
}

return results;

// Check if the file hash already exists in Document_Log
const currentItem = $('Generate Hash + ID').first().json;
const fileHash = currentItem.fileHash;
const existingDocs = $input.all().map(i => i.json);

const duplicate = existingDocs.find(doc =>
  doc.file_hash_sha256 === fileHash && doc.file_hash_sha256 !== 'no_binary'
);

return [{
  json: {
    ...currentItem,
    isDuplicate: !!duplicate,
    duplicateOfDocId: duplicate ? duplicate.doc_id : null,
  },
  binary: $('Generate Hash + ID').first().binary,
}];

// Extract input parameters from the trigger
const input = $input.first().json;

return [{
  json: {
    docId: input.doc_id || input.docId || 'TEST-DOC',
    rawDriveFileId: input.raw_drive_file_id || input.rawDriveFileId || '',
    fileName: input.original_filename || input.fileName || 'test.pdf',
    mimeType: input.mimeType || 'application/pdf',
    senderEmail: input.sender_email || input.senderEmail || '',
    subject: input.email_subject || input.subject || '',
    intakeTimestamp: input.intake_timestamp || input.intakeTimestamp || new Date().toISOString(),
  }
}];

// Non-PDF file - send to review queue
const input = $('Extract Input').first().json;
return [{
  json: {
    ...input,
    reviewReason: 'non_pdf_format',
    aiDocType: 'Other',
    aiConfidence: 0,
  }
}];

// Prepare Document AI OCR request
const input = $('Extract Input').first().json;
const binaryData = $('Download from Drive').first().binary?.data;

if (!binaryData || !binaryData.data) {
  return [{ json: { ...input, ocrText: '', ocrFailed: true } }];
}

// Build Document AI endpoint
const projectId = 'REPLACE_DOCAI_PROJECT';
const location = 'us';
const processorId = 'REPLACE_DOCAI_PROCESSOR';

return [{
  json: {
    ...input,
    docaiEndpoint: `https://${location}-documentai.googleapis.com/v1/projects/${projectId}/locations/${location}/processors/${processorId}:process`,
    rawDocument: {
      content: binaryData.data,
      mimeType: 'application/pdf',
    },
  }
}];

// Extract text from Document AI response
const input = $('Extract Input').first().json;
const response = $input.first().json;

let ocrText = '';
try {
  ocrText = response.document?.text || '';
} catch (e) {
  ocrText = '';
}

const hasText = ocrText.trim().length > 100;

return [{
  json: {
    ...input,
    extractedText: ocrText,
    textSource: 'ocr',
    hasText,
    reviewReason: hasText ? '' : 'no_text',
    aiDocType: hasText ? '' : 'Other',
    aiConfidence: hasText ? null : 0,
  }
}];

// Parse AI classification response
const input = $('Extract Input').first().json;
const response = $input.first().json;

let classification = {};
try {
  let content = response.choices[0].message.content || '';
  // Strip markdown fencing if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    doc_type: 'Other',
    confidence: 0,
    property_address: null,
    notes: 'Failed to parse AI response: ' + e.message,
  };
}

// Validate doc_type
const validTypes = [
  'FICA', 'Offer_to_Purchase', 'Mandate', 'Title_Deed',
  'Municipal_Document', 'Bond_Finance', 'Compliance_Certificate',
  'Sectional_Scheme', 'Entity_Document', 'Other'
];
if (!validTypes.includes(classification.doc_type)) {
  classification.doc_type = 'Other';
  classification.confidence = Math.min(classification.confidence || 0, 0.5);
}

return [{
  json: {
    docId: input.docId,
    rawDriveFileId: input.rawDriveFileId,
    fileName: input.fileName,
    mimeType: input.mimeType,
    senderEmail: input.senderEmail,
    subject: input.subject,
    intakeTimestamp: input.intakeTimestamp,
    docType: classification.doc_type || 'Other',
    confidence: classification.confidence || 0,
    propertyAddress: classification.property_address || '',
    erfNumber: classification.erf_number || '',
    unitNumber: classification.unit_number || '',
    schemeName: classification.scheme_name || '',
    city: classification.city || '',
    suburb: classification.suburb || '',
    province: classification.province || '',
    buyerName: classification.buyer_name || '',
    sellerName: classification.seller_name || '',
    agentName: classification.agent_name || '',
    transactionDate: classification.transaction_date || '',
    referenceNumber: classification.reference_number || '',
    aiNotes: classification.notes || '',
  }
}];

// Flag for review - low confidence
return [{
  json: {
    ...$json,
    reviewReason: 'low_confidence',
    aiDocType: $json.docType,
    aiConfidence: $json.confidence,
  }
}];

// Match document to existing property
const doc = $('Parse AI Response').first().json;
const properties = $input.all().map(i => i.json);

let bestMatch = null;
let bestScore = 0;

for (const prop of properties) {
  if (!prop.property_id) continue;
  let score = 0;

  // Exact erf match (highest priority)
  if (doc.erfNumber && prop.erf_number && doc.erfNumber === prop.erf_number) {
    score += 100;
  }

  // Unit + scheme match
  if (doc.unitNumber && prop.unit_number && doc.unitNumber === prop.unit_number
      && doc.schemeName && prop.scheme_name && doc.schemeName.toLowerCase() === prop.scheme_name.toLowerCase()) {
    score += 90;
  }

  // Address fuzzy match
  if (doc.propertyAddress && prop.display_address) {
    const docAddr = doc.propertyAddress.toLowerCase().replace(/[^a-z0-9]/g, '');
    const propAddr = prop.display_address.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (docAddr === propAddr) {
      score += 80;
    } else if (propAddr.includes(docAddr) || docAddr.includes(propAddr)) {
      score += 60;
    } else {
      // Token overlap
      const docTokens = doc.propertyAddress.toLowerCase().split(/\s+/);
      const propTokens = prop.display_address.toLowerCase().split(/\s+/);
      const overlap = docTokens.filter(t => propTokens.includes(t) && t.length > 2).length;
      if (overlap >= 3) score += 40;
    }
  }

  if (score > bestScore) {
    bestScore = score;
    bestMatch = prop;
  }
}

const matched = bestScore >= 40;
const docTypeFolderMap = {"FICA": "01_FICA", "Offer_to_Purchase": "02_OTP", "Mandate": "03_Mandate", "Title_Deed": "04_Title_Deed", "Municipal_Document": "05_Municipal", "Bond_Finance": "06_Bond_Finance", "Compliance_Certificate": "07_Compliance", "Sectional_Scheme": "08_Sectional_Scheme", "Entity_Document": "09_Entity_Docs", "Other": "10_Other"};

return [{
  json: {
    ...doc,
    propertyMatched: matched,
    matchScore: bestScore,
    matchedPropertyId: matched ? bestMatch.property_id : null,
    matchedAddress: matched ? bestMatch.display_address : null,
    matchedDriveFolderId: matched ? bestMatch.drive_folder_id : null,
    categoryFolder: docTypeFolderMap[doc.docType] || '10_Other',
  }
}];

// Build the Google Drive folder path for this document
const doc = $('Match Property').first().json;
const createResult = $input.first().json;

// Determine property ID - either matched or newly created
const propertyId = doc.matchedPropertyId || createResult.property_id || doc.docId;
const city = doc.city || 'Unknown_City';
const suburb = doc.suburb || 'Unknown_Suburb';
const displayAddress = doc.propertyAddress || doc.matchedAddress || 'Unknown_Address';

// Clean folder names (remove invalid chars)
const clean = (s) => s.replace(/[<>:"/\\|?*]/g, '_').trim() || 'Unknown';

return [{
  json: {
    ...doc,
    propertyId: propertyId,
    cityFolder: clean(city),
    suburbFolder: clean(suburb),
    addressFolder: clean(displayAddress),
    categoryFolder: doc.categoryFolder,
    propertiesRootId: 'REPLACE_PROPERTIES',
    // File rename
    newFileName: `${$now.format('yyyy-MM-dd')}_${doc.docType}_${doc.referenceNumber || 'NOREF'}_${doc.fileName}`,
  }
}];

// This node orchestrates folder creation and file move via
// Google Drive API. Each folder is searched first, created if missing.
// The final step moves the raw file into the category subfolder.
//
// NOTE: This uses $getWorkflowStaticData to cache folder IDs
// across executions for performance.

const doc = $json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.folderCache) staticData.folderCache = {};

// Return instructions for downstream Google Drive nodes
return [{
  json: {
    ...doc,
    folderPath: `${doc.cityFolder}/${doc.suburbFolder}/${doc.addressFolder}/${doc.categoryFolder}`,
    // These will be populated by the folder creation chain
    step: 'ready_for_folders',
  }
}];

// Build folder creation plan
// This node prepares the data for sequential folder creation
const doc = $('Prepare Folder Chain').first().json;
const searchResults = $input.all().map(i => i.json);

let cityFolderId = '';
if (searchResults.length > 0 && searchResults[0].id) {
  cityFolderId = searchResults[0].id;
}

return [{
  json: {
    ...doc,
    cityFolderId,
    needsCreateCity: !cityFolderId,
  }
}];

// After creating city folder, we need to create suburb, address,
// and category subfolders. For simplicity, we'll use a single Code
// node that outputs the folder IDs for the remaining chain.
//
// In production, each folder level would be its own search+create pair.
// For MVP, we'll move the file to the city folder and create the
// subfolders in subsequent iterations.

const doc = $('Check City Result').first().json;
const createResult = $input.first().json;

const cityFolderId = doc.cityFolderId || createResult.id || '';

return [{
  json: {
    ...doc,
    cityFolderId,
    targetFolderId: cityFolderId, // MVP: file at city level
    rawDriveFileId: doc.rawDriveFileId,
    newFileName: doc.newFileName,
  }
}];

// Filter for items where admin has filled in an action but status is still open
const items = $input.all();
const actionable = items.filter(item => {
  const row = item.json;
  return row.admin_action
    && row.admin_action.trim() !== ''
    && row.status === 'open'
    && row.admin_email
    && row.admin_email.trim() !== '';
});

if (actionable.length === 0) {
  return [{ json: { _noItems: true, count: 0 } }];
}

return actionable;

// Match review item to its document record and prepare updates
const reviewItem = $('Filter Actionable').first().json;
const allDocs = $input.all().map(i => i.json);

const docRecord = allDocs.find(d => d.doc_id === reviewItem.doc_id);

if (!docRecord) {
  return [{ json: { error: 'Document not found: ' + reviewItem.doc_id, reviewItem } }];
}

const action = reviewItem.admin_action.trim().toLowerCase();
const docTypeFolderMap = {"FICA": "01_FICA", "Offer_to_Purchase": "02_OTP", "Mandate": "03_Mandate", "Title_Deed": "04_Title_Deed", "Municipal_Document": "05_Municipal", "Bond_Finance": "06_Bond_Finance", "Compliance_Certificate": "07_Compliance", "Sectional_Scheme": "08_Sectional_Scheme", "Entity_Document": "09_Entity_Docs", "Other": "10_Other"};

let finalDocType = docRecord.doc_type;
let finalPropertyId = docRecord.property_id;
let status = 'processed';

if (action === 'reclassify' && reviewItem.correct_doc_type) {
  finalDocType = reviewItem.correct_doc_type;
}
if (reviewItem.correct_property_id) {
  finalPropertyId = reviewItem.correct_property_id;
}
if (action === 'flag_error') {
  status = 'error';
}

return [{
  json: {
    reviewId: reviewItem.review_id,
    docId: reviewItem.doc_id,
    action,
    adminEmail: reviewItem.admin_email,
    adminNotes: reviewItem.admin_notes || '',
    finalDocType,
    finalPropertyId,
    status,
    rawDriveFileId: docRecord.raw_drive_file_id,
    categoryFolder: docTypeFolderMap[finalDocType] || '10_Other',
    originalStatus: docRecord.status,
    originalDocType: docRecord.doc_type,
  }
}];

// Build daily summary statistics
const reviews = $('Read Reviews').all().map(i => i.json);
const docs = $('Read Documents').all().map(i => i.json);

const today = new Date().toISOString().split('T')[0];

// Filter today's documents
const todayDocs = docs.filter(d => (d.intake_timestamp || '').startsWith(today));

// Count by status
const processed = todayDocs.filter(d => d.status === 'processed').length;
const pending = todayDocs.filter(d => d.status === 'pending').length;
const reviewRequired = todayDocs.filter(d => d.status === 'review_required').length;
const errors = todayDocs.filter(d => d.status === 'error').length;
const duplicates = todayDocs.filter(d => d.status === 'duplicate').length;

// Open reviews (any date)
const openReviews = reviews.filter(r => r.status === 'open');

// Count by doc type (all time today)
const typeCounts = {};
for (const doc of todayDocs) {
  const t = doc.doc_type || 'Unknown';
  typeCounts[t] = (typeCounts[t] || 0) + 1;
}

// Average confidence
const confidences = todayDocs
  .filter(d => d.doc_type_confidence)
  .map(d => parseFloat(d.doc_type_confidence));
const avgConfidence = confidences.length > 0
  ? (confidences.reduce((a, b) => a + b, 0) / confidences.length).toFixed(2)
  : 'N/A';

// Build type breakdown HTML
let typeBreakdown = '';
for (const [type, count] of Object.entries(typeCounts).sort((a, b) => b[1] - a[1])) {
  typeBreakdown += `<tr><td>${type}</td><td>${count}</td></tr>`;
}

// Build open review list HTML
let reviewList = '';
for (const r of openReviews.slice(0, 20)) {
  reviewList += `<tr>
    <td>${r.review_id || ''}</td>
    <td>${r.original_filename || ''}</td>
    <td>${r.reason || ''}</td>
    <td>${r.ai_doc_type || ''}</td>
    <td>${r.ai_confidence || ''}</td>
    <td><a href="${r.raw_drive_url || '#'}">View</a></td>
  </tr>`;
}

return [{
  json: {
    date: today,
    totalToday: todayDocs.length,
    processed,
    pending,
    reviewRequired,
    errors,
    duplicates,
    openReviewCount: openReviews.length,
    avgConfidence,
    typeBreakdown,
    reviewList,
    hasOpenReviews: openReviews.length > 0,
  }
}];

// Format error details from the error trigger
const error = $input.first().json;

const workflowName = error.workflow?.name || 'Unknown Workflow';
const nodeName = error.execution?.error?.node?.name || 'Unknown Node';
const errorMessage = error.execution?.error?.message || 'No error message';
const executionId = error.execution?.id || '';
const timestamp = new Date().toISOString();

return [{
  json: {
    workflowName,
    nodeName,
    errorMessage,
    executionId,
    timestamp,
    subject: `[ERROR] Document Intake - ${workflowName} failed at ${nodeName}`,
    body: `<h3 style="color: red;">Document Intake Error</h3>
<p><strong>Workflow:</strong> ${workflowName}</p>
<p><strong>Node:</strong> ${nodeName}</p>
<p><strong>Error:</strong> ${errorMessage}</p>
<p><strong>Execution ID:</strong> ${executionId}</p>
<p><strong>Time:</strong> ${timestamp}</p>
<p>Check the n8n execution log for details.</p>`,
  }
}];
